def trimmed_mean(nums):
    if not nums:
        return None

    nums = sorted(nums)
    min_occurrence = nums[0]
    max_occurrence = nums[-1]
    nums.remove(min_occurrence)
    nums.remove(max_occurrence)
    nums_len = len(nums)

    if nums_len % 2 == 0:
        return sum(nums) / nums_len
    else:
        return sum(nums[:nums_len//2 + 1]) / (nums_len // 2 + 1)
